class Solution {
public:
    int maxAbsValExpr(vector<int>& arr1, vector<int>& arr2) {
        int n = arr1.size();
        int res = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                res = max(res, abs(arr1[i] - arr1[j]) + abs(arr2[i] - arr2[j]) + abs(i - j));
                res = max(res, abs(arr1[i] + arr1[j]) + abs(arr2[i] + arr2[j]) + abs(i + j));
                res = max(res, abs(arr1[i] - arr1[j]) + abs(arr2[i] + arr2[j]) + abs(i - j));
                res = max(res, abs(arr1[i] + arr1[j]) + abs(arr2[i] - arr2[j]) + abs(i + j));
            }
        }
        return res;
    }
};
